#include <functional>
#include <type_traits>
#include <memory>
#include <algorithm>
#include <vector>
#include <random>
#include <iostream>

// std::result_of is deprecated; use std::invoke_result instead
template<typename F, typename... Args>
using my_result_t = std::invoke_result_t<F, Args...>;

// std::is_pod is deprecated; use is_trivial && is_standard_layout
template<typename T>
constexpr bool is_pod_like = std::is_trivial_v<T> && std::is_standard_layout_v<T>;

// std::binary_function was removed; lambdas replaced it
// Old: struct Add : std::binary_function<int, int, int> { ... };
// New: auto add = [](int a, int b) { return a + b; };

// std::random_shuffle was removed; use std::shuffle instead
void demo_shuffle(std::vector<int>& v) {
    std::mt19937 rng(42);  // fixed seed for determinism
    std::shuffle(v.begin(), v.end(), rng);
}

int main() {
    // invoke_result instead of result_of
    using T = my_result_t<decltype([](int x) { return x * 2.0; }), int>;
    std::cout << "result type is double: " << std::is_same_v<T, double> << "\n";

    // is_trivial + is_standard_layout instead of is_pod
    struct Plain { int x; double y; };
    struct WithVirtual { virtual void f() {} };
    std::cout << "Plain is pod-like: " << is_pod_like<Plain> << "\n";          // 1
    std::cout << "Virtual is pod-like: " << is_pod_like<WithVirtual> << "\n";  // 0

    // std::shuffle instead of random_shuffle
    std::vector<int> v{1, 2, 3, 4, 5};
    demo_shuffle(v);
    std::cout << "shuffled: ";
    for (int x : v) std::cout << x << " ";
    std::cout << "\n";

    // allocator_traits instead of allocator::construct
    std::allocator<int> alloc;
    int* p = std::allocator_traits<std::allocator<int>>::allocate(alloc, 1);
    std::allocator_traits<std::allocator<int>>::construct(alloc, p, 42);
    std::cout << "constructed: " << *p << "\n";
    std::allocator_traits<std::allocator<int>>::destroy(alloc, p);
    std::allocator_traits<std::allocator<int>>::deallocate(alloc, p, 1);
}

#include <iostream>
#include <atomic>
#include <type_traits>
#include <iterator>

int main() {
    // Instead of volatile int for thread-shared state, use atomic:
    std::atomic<int> counter{0};
    counter += 1;       // fine (atomic compound assignment)
    counter.fetch_add(1);  // explicit form
    std::cout << "counter: " << counter.load() << "\n";

    // volatile is still valid for memory-mapped I/O (hardware registers)
    // Only specific patterns are deprecated:
    // - volatile as parameter:    void f(volatile int)  -- deprecated
    // - compound assignments:     v += 1               -- deprecated
    // - volatile as return type:  volatile int f()      -- deprecated

    // std::iterator as base class is deprecated.
    // Old: struct MyIter : std::iterator<std::forward_iterator_tag, int> { ... };
    // New: declare associated types as explicit member typedefs:
    struct ModernIterator {
        using iterator_category = std::forward_iterator_tag;
        using value_type        = int;
        using difference_type   = std::ptrdiff_t;
        using pointer           = int*;
        using reference         = int&;
        // ... implementation
    };

    std::cout << "ModernIterator is valid: "
              << std::is_same_v<ModernIterator::value_type, int> << "\n";
}
